-- ===== PART 2: Remove duplicate test cases =====

DROP TABLE IF EXISTS matura_db._dedup_keep;

CREATE TABLE matura_db._dedup_keep AS
SELECT MIN(id) AS id FROM matura_db.algo_task_tests
GROUP BY task_id, test_name, input_data, expected;

DELETE FROM matura_db.algo_task_tests
WHERE id NOT IN (SELECT id FROM matura_db._dedup_keep);

DROP TABLE matura_db._dedup_keep;

-- ===== PART 3: Remove duplicate quiz questions =====

DROP TABLE IF EXISTS matura_db._dedup_quiz_keep;

CREATE TABLE matura_db._dedup_quiz_keep AS
SELECT MIN(id) AS id FROM matura_db.quiz_questions
GROUP BY category, question;

DELETE FROM matura_db.quiz_questions
WHERE id NOT IN (SELECT id FROM matura_db._dedup_quiz_keep);

DROP TABLE matura_db._dedup_quiz_keep;

-- ===== Verification =====
SELECT 'algo_tasks' AS tbl, COUNT(*) AS cnt FROM matura_db.algo_tasks
UNION ALL
SELECT 'algo_task_tests', COUNT(*) FROM matura_db.algo_task_tests
UNION ALL
SELECT 'quiz_questions', COUNT(*) FROM matura_db.quiz_questions;
